def has_won_both_wsop_and_wsope(player_wins):
    wsop_wins = {'WSOP Main Event', 'WSOP Circuit Event', 'WSOP Bracelet Event'}
    wsope_wins = {'WSOPE Main Event', 'WSOPE Bracelet Event'}

    has_wsop = any(win in wsop_wins for win in player_wins)
    has_wsope = any(win in wsope_wins for win in player_wins)

    return has_wsop and has_wsope

# Example usage:
player_wins = ['WSOP Main Event', 'WSOPE Bracelet Event', 'EPT Event']
print(has_won_both_wsop_and_wsope(player_wins))  # Output: True
